CREATE CACHED TABLE IF NOT EXISTS "SCRIPTS_RUN" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "CREATETIMESTAMP" TIMESTAMP NULL,
    "OUTCOME" VARCHAR(32) NOT NULL,
    "SUMMARY" VARCHAR(8388608) NOT NULL
);

CREATE CACHED TABLE IF NOT EXISTS "SCRIPTS_RUN_SCRIPT" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "RUNID" BIGINT NOT NULL,
    "ORDINAL" INT NOT NULL,
    "SCRIPTNAME" VARCHAR(4096) NOT NULL,
    "SCRIPTTYPE" VARCHAR(1024) NOT NULL,
    CONSTRAINT "SCRIPTS_RUN_SCRIPT_FK_RUN" FOREIGN KEY ("RUNID") REFERENCES "SCRIPTS_RUN" ("ID")
);

CREATE CACHED TABLE IF NOT EXISTS "SCRIPTS_RUN_STEP" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "RUNSCRIPTID" BIGINT NOT NULL,
    "ORDINAL" INT NOT NULL,
    "SOURCESTEPINDEX" INT NOT NULL,
    "LINETEXT" VARCHAR(1024) NOT NULL,
    CONSTRAINT "SCRIPTS_RUN_STEP_FK_SCRIPT" FOREIGN KEY ("RUNSCRIPTID") REFERENCES "SCRIPTS_RUN_SCRIPT" ("ID")
);

CREATE CACHED TABLE IF NOT EXISTS "SCRIPTS_RUN_OUTPUT" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "RUNSTEPID" BIGINT NOT NULL,
    "ORDINAL" INT NOT NULL,
    "KIND" VARCHAR(32) NOT NULL,
    "MESSAGE" VARCHAR(8388608) NOT NULL,
    CONSTRAINT "SCRIPTS_RUN_OUTPUT_FK_STEP" FOREIGN KEY ("RUNSTEPID") REFERENCES "SCRIPTS_RUN_STEP" ("ID")
);
